<?php declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';vp3_require_admin_permission('customers.view');$pageTitle='Customers';require VP3_ROOT.'/includes/admin-header.php';$q=vp3_input('q');$sql='SELECT id,customer_uuid,name,company_name,email,status,created_at FROM customers';$params=[];if($q!==''){$sql.=' WHERE name LIKE ? OR email LIKE ? OR company_name LIKE ?';$params=array_fill(0,3,'%'.$q.'%');}$sql.=' ORDER BY id DESC LIMIT 250';$s=vp3_db()->prepare($sql);$s->execute($params);$rows=$s->fetchAll();?><h1>Customers</h1><form method="get" class="hero-actions"><input name="q" value="<?=vp3_e($q)?>" placeholder="Search customers"><button class="button small">Search</button></form><div class="table-wrap"><table class="table"><thead><tr><th>Name</th><th>Company</th><th>Email</th><th>Status</th><th>Created</th><th></th></tr></thead><tbody><?php foreach($rows as $x):?><tr><td><?=vp3_e($x['name'])?></td><td><?=vp3_e($x['company_name'])?></td><td><?=vp3_e($x['email'])?></td><td><span class="badge <?=vp3_e($x['status'])?>"><?=vp3_e($x['status'])?></span></td><td><?=vp3_e($x['created_at'])?></td><td><a href="customer.php?id=<?=(int)$x['id']?>">Open</a></td></tr><?php endforeach;?></tbody></table></div><?php require VP3_ROOT.'/includes/admin-footer.php';?>